import{_ as e,o as l,c as a,a2 as d}from"./chunks/framework.DnrXFDHb.js";const x=JSON.parse('{"title":"F02: 營業現金流與獲利品質 — 財務分析專家審計報告","description":"","frontmatter":{},"headers":[],"relativePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F02_營業現金流與獲利品質.md","filePath":"審計報告庫/財務審計/8103_瀚荃/20260425/F02_營業現金流與獲利品質.md"}'),n={name:"審計報告庫/財務審計/8103_瀚荃/20260425/F02_營業現金流與獲利品質.md"};function i(s,t,r,o,h,g){return l(),a("div",null,[...t[0]||(t[0]=[d('<h1 id="f02-營業現金流與獲利品質-—-財務分析專家審計報告" tabindex="-1">F02: 營業現金流與獲利品質 — 財務分析專家審計報告 <a class="header-anchor" href="#f02-營業現金流與獲利品質-—-財務分析專家審計報告" aria-label="Permalink to &quot;F02: 營業現金流與獲利品質 — 財務分析專家審計報告&quot;">​</a></h1><p><strong>標的公司</strong>：8103 瀚荃 | <strong>審計日期</strong>：2026-04-25 | <strong>數據截至</strong>：FY2025（2025/12）</p><hr><h2 id="📋-審計題目" tabindex="-1">📋 審計題目 <a class="header-anchor" href="#📋-審計題目" aria-label="Permalink to &quot;📋 審計題目&quot;">​</a></h2><p>營業活動現金流量 (CFO) 與稅後淨利之關係為何？獲利是否具備實質現金支撐？</p><hr><h2 id="🎯-專家直斷" tabindex="-1">🎯 專家直斷 <a class="header-anchor" href="#🎯-專家直斷" aria-label="Permalink to &quot;🎯 專家直斷&quot;">​</a></h2><p>根據截至 FY2025 最新公開數據，瀚荃 CFO 對淨利比長期維持 190% 以上（FY2024: 194.0%, FY2025: 190.9%），<strong>獲利含金量極高</strong>，每一元帳面淨利背後有近兩元實質現金流入。自由現金流連續兩年維持 5 億元以上（FY2024: 5.49 億, FY2025: 5.19 億），營運資金管理優異，折舊攤銷佔 CFO 比約 31-34%，不存在「靠折舊撐起現金流」警訊。</p><hr><h2 id="📊-診斷評級" tabindex="-1">📊 診斷評級 <a class="header-anchor" href="#📊-診斷評級" aria-label="Permalink to &quot;📊 診斷評級&quot;">​</a></h2><p><strong>S（優）</strong> — CFO 連續兩年大幅超越稅後淨利（比率 &gt; 190%），FCF 同時為正且高達 5 億元以上，公司具備極強現金生成效率。營運資金周轉順暢，無「有獲利無現金」的空心化風險。唯一瑕疵：FY2025 CFO 較 FY2024 微降 1.3%，但絕對水位仍屬極優。</p><hr><h2 id="🔍-答詢詳解" tabindex="-1">🔍 答詢詳解 <a class="header-anchor" href="#🔍-答詢詳解" aria-label="Permalink to &quot;🔍 答詢詳解&quot;">​</a></h2><h3 id="_1-cfo-淨利比值測算-四年度對比" tabindex="-1">1. CFO / 淨利比值測算（四年度對比） <a class="header-anchor" href="#_1-cfo-淨利比值測算-四年度對比" aria-label="Permalink to &quot;1. CFO / 淨利比值測算（四年度對比）&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年度</th><th style="text-align:left;">CFO（百萬）</th><th style="text-align:left;">稅後淨利（百萬）</th><th style="text-align:left;">CFO/NI</th><th style="text-align:left;">判讀</th></tr></thead><tbody><tr><td style="text-align:left;">FY2023</td><td style="text-align:left;">714.1</td><td style="text-align:left;">187.1*</td><td style="text-align:left;">381.7%</td><td style="text-align:left;">淨利極低致比值畸高（Q4 業外損失拖累）</td></tr><tr><td style="text-align:left;">FY2024</td><td style="text-align:left;">655.0</td><td style="text-align:left;">337.6</td><td style="text-align:left;">194.0%</td><td style="text-align:left;">獲利含金量極高</td></tr><tr><td style="text-align:left;">FY2025</td><td style="text-align:left;">646.2</td><td style="text-align:left;">338.5</td><td style="text-align:left;">190.9%</td><td style="text-align:left;">獲利含金量維持極高水準</td></tr></tbody></table><p>*FY2023 淨利僅 1.87 億，主因 Q4 認列大額業外損失（-4.79 億），比值&gt;300% 屬基期效應失真。</p><p><strong>製造業標準</strong>：CFO/NI &gt; 100% 合格（因折舊等非現金加回），&gt; 150% 屬優異。瀚荃 190%+ 遠超行業標準。</p><h3 id="_2-非現金項目核實" tabindex="-1">2. 非現金項目核實 <a class="header-anchor" href="#_2-非現金項目核實" aria-label="Permalink to &quot;2. 非現金項目核實&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年度</th><th style="text-align:left;">折舊（百萬）</th><th style="text-align:left;">攤銷（百萬）</th><th style="text-align:left;">合計（百萬）</th><th style="text-align:left;">佔 CFO 比</th></tr></thead><tbody><tr><td style="text-align:left;">FY2023</td><td style="text-align:left;">226.0</td><td style="text-align:left;">12.2</td><td style="text-align:left;">238.2</td><td style="text-align:left;">33.4%</td></tr><tr><td style="text-align:left;">FY2024</td><td style="text-align:left;">221.4</td><td style="text-align:left;">15.7</td><td style="text-align:left;">237.1</td><td style="text-align:left;">36.2%</td></tr><tr><td style="text-align:left;">FY2025</td><td style="text-align:left;">204.9</td><td style="text-align:left;">15.2</td><td style="text-align:left;">220.1</td><td style="text-align:left;">34.1%</td></tr></tbody></table><p>折舊佔 CFO 約 33-36%，屬正常範圍（製造業 30-50%）。扣除折舊後 CFO 仍為正（646.2−204.9=441.3M），現金流來自真實營運周轉效率。</p><h3 id="_3-營運資金變動分析" tabindex="-1">3. 營運資金變動分析 <a class="header-anchor" href="#_3-營運資金變動分析" aria-label="Permalink to &quot;3. 營運資金變動分析&quot;">​</a></h3><p><strong>FY2025 營運資金變動對 CFO 貢獻</strong>：</p><table tabindex="0"><thead><tr><th style="text-align:left;">項目</th><th style="text-align:left;">金額（百萬）</th><th style="text-align:left;">對 CFO 影響</th></tr></thead><tbody><tr><td style="text-align:left;">應收帳款減少</td><td style="text-align:left;">-52.4</td><td style="text-align:left;">+52.4（正向）</td></tr><tr><td style="text-align:left;">存貨減少</td><td style="text-align:left;">-51.1</td><td style="text-align:left;">+51.1（正向）</td></tr><tr><td style="text-align:left;">應付帳款增加</td><td style="text-align:left;">+106.9</td><td style="text-align:left;">+106.9（正向）</td></tr><tr><td style="text-align:left;">合計</td><td style="text-align:left;">—</td><td style="text-align:left;">+210.4</td></tr></tbody></table><p>FY2024 對比：應收 -102.5M、存貨 -30.2M、應付 +138.1M，合計 +270.8M。</p><p><strong>空頭視角</strong>：FY2025Q1 單季應收帳款曾增加 100.2M（現金流出），季度波動需關注。若 AI 客戶延後付款（CSP 付款週期 60-90 天），季度 CFO 可能波動加大。</p><h3 id="_4-自由現金流-fcf-穿透" tabindex="-1">4. 自由現金流 (FCF) 穿透 <a class="header-anchor" href="#_4-自由現金流-fcf-穿透" aria-label="Permalink to &quot;4. 自由現金流 (FCF) 穿透&quot;">​</a></h3><table tabindex="0"><thead><tr><th style="text-align:left;">年度</th><th style="text-align:left;">CFO（百萬）</th><th style="text-align:left;">CapEx（百萬）</th><th style="text-align:left;">FCF（百萬）</th><th style="text-align:left;">FCF/NI</th></tr></thead><tbody><tr><td style="text-align:left;">FY2023</td><td style="text-align:left;">714.1</td><td style="text-align:left;">84.2</td><td style="text-align:left;">629.9</td><td style="text-align:left;">336.5%</td></tr><tr><td style="text-align:left;">FY2024</td><td style="text-align:left;">655.0</td><td style="text-align:left;">106.4</td><td style="text-align:left;">548.6</td><td style="text-align:left;">162.5%</td></tr><tr><td style="text-align:left;">FY2025</td><td style="text-align:left;">646.2</td><td style="text-align:left;">127.4</td><td style="text-align:left;">518.8</td><td style="text-align:left;">153.3%</td></tr></tbody></table><p>FCF 逐年略降（629.9→548.6→518.8），主因 CapEx 增加（84.2→106.4→127.4），反映泰國、越南擴產投入。但 FCF/NI 仍達 153%，遠超 100% 安全線。FY2025 CapEx 1.27 億與資產負債表不動產變動一致，真實性可驗證。</p><hr><h2 id="💡-專家評析" tabindex="-1">💡 專家評析 <a class="header-anchor" href="#💡-專家評析" aria-label="Permalink to &quot;💡 專家評析&quot;">​</a></h2><h3 id="華爾街空頭視角-skepticism" tabindex="-1">華爾街空頭視角（Skepticism） <a class="header-anchor" href="#華爾街空頭視角-skepticism" aria-label="Permalink to &quot;華爾街空頭視角（Skepticism）&quot;">​</a></h3><p><strong>極端風險情境</strong>：</p><ol><li><p><strong>CFO 高位可持續性</strong>：FY2025 CFO 部分來自「應收減少」與「存貨減少」的一次性貢獻（合計 +103.5M）。若 FY2026 AI 訂單暴增導致備貨需求上升，存貨可能轉為現金流出，壓縮 CFO。</p></li><li><p><strong>應付帳款膨脹極限</strong>：FY2025 應付增加 106.9M，較 FY2024 的 138.1M 減少 22.7%，對供應商延後付款空間正在收斂。若供應商要求縮短付款期限，將直接衝擊 CFO。</p></li><li><p><strong>折舊遞延效應</strong>：FY2025 折舊 204.9M 較 FY2024 減少 16.5M（部分資產攤提完畢）。但泰國、越南新產能投產後折舊將回升，對 CFO/NI 產生「虛降」效果。</p></li><li><p><strong>業外損失幽靈</strong>：FY2023 Q4 業外損失 -47.9M 致全年淨利僅 12.2M；FY2025Q2 亦有 -49.2M 業外支出（含匯兌）。投資人應以「CFO/營業利益」交叉驗證：FY2024=655.0/364.6=179.7%，FY2025=646.2/449.5=143.8%，仍在健康範圍。</p></li></ol><p><strong>物理對策</strong>：關注季度營運資金變動，若連續 2 季以上出現「應收+存貨增加」的死亡組合，即為 CFO 惡化早期訊號。CapEx/折舊比從 0.48 上升至 0.62，新產能投資回報率需持續觀察。</p><hr><h2 id="📚-證據來源" tabindex="-1">📚 證據來源 <a class="header-anchor" href="#📚-證據來源" aria-label="Permalink to &quot;📚 證據來源&quot;">​</a></h2><ol><li><strong>FinMind 數據採集器</strong> — <code>cash_flow 8103 2023-04-25 2026-04-25 --df</code>（CFO、折舊、攤銷、營運資金變動、CapEx）</li><li><strong>FinMind 數據採集器</strong> — <code>finance 8103 2023-04-25 2026-04-25 --df</code>（稅後淨利、營業利益）</li><li><strong>Python 計算腳本</strong> — <code>/tmp/hanchuan_audit_calc.py</code>（CFO/NI、FCF、營運資金拆解）</li></ol>',37)])])}const y=e(n,[["render",i]]);export{x as __pageData,y as default};
